-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 019 — SQL con Oracle · m06: Joins y subqueries
-- ═══════════════════════════════════════════════════════════════════
-- Cubre la Parte IX en su tramo multi-tabla: INNER JOIN en sintaxis
-- ANSI, OUTER joins (LEFT/RIGHT/FULL), self join (la recursiva del
-- m3a hecha consulta), CROSS JOIN/producto cartesiano, NATURAL JOIN
-- y USING (y por qué el oficio prefiere ON), operadores de conjunto
-- (UNION, UNION ALL, INTERSECT, MINUS) y subconsultas: de una fila,
-- multifila (IN/ANY/ALL), correladas, EXISTS/NOT EXISTS con la
-- trampa de NOT IN + nulos, e inline views.
-- Práctica de editor (regex+mockOutput): el anti-join clásico
-- (pacientes sin citas: LEFT JOIN + IS NULL).
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm06-joins-subqueries'
);

